  get name() {
    console.log("Геттер вызван");
    return this._name;
  }

  set name(value) {
    console.log("Сеттер вызван");
    if (value.length < 2) throw new Error("Имя слишком короткое");
    this._name = value;
  }
}

const u = new User("Тим");

console.log(u.name); // 🟢 Геттер вызван → "Тим"
